 {
     new { Churned = "Yes", Label = true },
     new { Churned = "No",  Label = false }
 });

 var pipeline = mlContext.Transforms.Conversion.MapValue(
         "Label", labelLookupData, labelLookupData.Schema["Churned"], labelLookupData.Schema["Label"],
         inputColumnName: nameof(ChurnInput.Churned))
     .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region)))
     .Append(mlContext.Transforms.Concatenate("Features",
         nameof(ChurnInput.Age), nameof(ChurnInput.Income), "RegionEncoded", nameof(ChurnInput.PurchaseHistory)))
     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
         labelColumnName: "Label", featureColumnName: "Features"));

 var rowCount = (int)allData.GetColumn<float>(nameof(ChurnInput.Age)).Count();

 // Use train/test split only when there are enough rows for meaningful evaluation
 if (rowCount >= 20)
 {
     var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2);
     var model = pipeline.Fit(split.TrainSet);
     var predictions = model.Transform(split.TestSet);
     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
     Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

     var trainedOnAll = pipeline.Fit(allData);
     var modelPathSplit = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
     mlContext.Model.Save(trainedOnAll, allData.Schema, modelPathSplit);
 }
 else
 {
     Console.WriteLine($"Dataset has {rowCount} rows — too small for train/test split. Training on all data.");
     var model = pipeline.Fit(allData);
     var modelPathSmall = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
     mlContext.Model.Save(model, allData.Schema, modelPathSmall);
 }

